var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"다녀왔습니다아......","JPN":"ただいま……","ENG":"I'm back...","TWN":"我回來了……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"후아...... 힘들었다......","JPN":"ふわぁ……疲れた……","ENG":"Phew... What a day...","TWN":"呼……好累……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"침식체 때문에 난리가 났는데 어딜 쏘다니다 이제 온 거야?","JPN":"侵食体のせいで大変なことになっていたのに、今までどこに行ってた？","ENG":"Where have you been all this time? We had to deal with all those C.O.s!","TWN":"外面被侵蝕體鬧得一團糟，妳怎麼還有心情在外面閒逛？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤, 누굴 좀 도와드리느라요.","JPN":"えへへ、人助けをしてきました。","ENG":"Heh, I was just helping someone out.","TWN":"嘿嘿，我幫人去了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"네가 사람을 도와 줄 수도 있구나. 누군지 얼굴 한 번 보고 싶네.","JPN":"汝に人を助ける力があったのか？　誰なのか顔をみてみたい。","ENG":"Oh, I didn't know you were capable of actually helping for once. I wonder who the lucky person is.","TWN":"妳還會幫人？真想看看那人長什麼樣子。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"우으...... 서빙하다 접시 깬 건 잘못했다니까요......","JPN":"うう……接客中にお皿を割ってしまったことについてはごめんなさい……","ENG":"Aw... I told you I'm sorry for breaking those plates while serving...","TWN":"呃……端盤的時候打破盤子確實是我的不對……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"졸다가 손님 머리 위에 커피 쏟은 건?","JPN":"うっかり眠ってしまってお客さんの頭にコーヒーをこぼしたことは？","ENG":"And what about spilling coffee on the customer's head while dozing off?","TWN":"那打瞌睡把咖啡撒到客人頭上的事呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"죄송합니다아......","JPN":"ごめんなさい……","ENG":"I'm sorry about that, too...","TWN":"對不起……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 됐어.","JPN":"まぁ、いい。","ENG":"Forget it.","TWN":"唉，算了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그보다 잉그리드는? 같이 있던 거 아니었어?","JPN":"それより、イングリッドは？　一緒じゃなかったのか？","ENG":"Where's Ingrid by the way? Wasn't she with you?","TWN":"對了，英格麗呢？她不是和妳在一起嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아뇨. 잉그리드라면 이면세계에서 돌아온 뒤로 계속 자기 방에 있던데요.","JPN":"はい。イングリッドは裏世界から帰ってきて以来、ずっと自分の部屋に閉じこもってます。","ENG":"No. Ingrid's been cooped up in her room ever since we came back from the Counterside.","TWN":"沒有，英格麗從異界回來之後就一直待在自己的房裡。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 사고뭉치가? 별일이네?","JPN":"あの問題児が？　珍しいな。","ENG":"That little rascal? Odd...","TWN":"那個搗蛋鬼沒湊熱鬧？真是奇怪。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이번에 꼭 시험을 통과하고 싶나 봐요. 바느질도 금방 배우더라고요.","JPN":"今度こそテストに合格したいみたいです。縫い物もすぐ覚えてました。","ENG":"She really seems to want to pass this test. She learned how to sew pretty quickly, too.","TWN":"她很想通過這次考試，縫紉也學得很快。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흐음...... 가서 안 도와 줘도 돼?","JPN":"ふーん……手伝わなくていいのか？","ENG":"Hmm... You sure you don't need to go help her?","TWN":"嗯……妳不用去幫幫她？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤. 형태는 어제 밤을 꼬박 새워서 거의 다 잡았어요.","JPN":"えへへ。昨日徹夜してほとんど完成したんです。","ENG":"Heh heh. We managed to get the shape right after an all-nighter.","TWN":"嘿嘿，昨天我們熬夜做好了外型輪廓了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그런데 마무리 작업은 꼭 혼자 하고 싶다고 해서요.","JPN":"でも、仕上げはどうしても一人でやりたいと言われたので。","ENG":"But she insisted that she finish it up by herself.","TWN":"不過收尾部分，她想自己來。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......그래, 어제 밤을 꼬박 새웠으니까 서빙할 때 그렇게 꾸벅꾸벅 졸지.","JPN":"……そうか。昨日徹夜したから、接客中にぼんやりしてたんだな。","ENG":"I see. No wonder you were dozing off all day.","TWN":"……是啊，就因為熬夜才不停地打瞌睡吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어머. 열심히 하는 모습을 보니 정말 기대해도 되겠는걸.","JPN":"あら。頑張ってる姿を見てるとますます楽しみだわ。","ENG":"Oh, Ingrid must be working so hard! I look forward to seeing how she does on the test.","TWN":"哎呀，看她這麼認真的樣子，我還有點期待呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"기대가 크면 실망도 큰 법이야.","JPN":"期待が大きければ大きいほど、失望も大きくなるわけだ。","ENG":"Don't get your hopes up.","TWN":"期待越大……失望就也會越大。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"경연 시작 전까지 완성이나 하면 다행이지.","JPN":"コンテスト開始前までに完成すればいいが。","ENG":"She'll be lucky if she finishes it before the contest.","TWN":"大賽開始前能完成就很不錯了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그리고 유나 너, 이리 와 봐.","JPN":"あと、ユナ。こっちに来い。","ENG":"As for you, Yuna, come here for a sec.","TWN":"尤娜，妳來一下。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 저요?","JPN":"え？　私ですか？","ENG":"Hmm? Me?","TWN":"啊？我嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래. 너한테 줄 게 있어.","JPN":"そうだ。汝に渡すものがある。","ENG":"Yeah, I've got something to give you.","TWN":"嗯，有東西要給妳。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"책......?","JPN":"本……？","ENG":"A book?","TWN":"書……？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"오래 전에 메이 할머니가 우리 카페에 맡기고 간 물건이야.","JPN":"昔、メイ婆さんがうちのカフェに預けたものだ。","ENG":"Granny May left it at the cafe a long time ago.","TWN":"這是很久之前梅伊奶奶交給我們的東西。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"딱히 누구한테 주란 얘기는 없었지만, 넌 할머니의 상속인이니까 네가 갖는 게 낫겠지.","JPN":"誰に渡してくれとは言われなかったが、\\n婆さんの相続人である汝が持っているほうがいいだろう。","ENG":"She didn't tell us to give it to anyone in particular, but I figured you should have it, seeing as you're her beneficiary.","TWN":"她沒說過把這本書給誰，不過既然妳是她的繼承人，交給妳最合適了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이거...... 무슨 동화책 같은 거예요? 엄청 낡아 보이는데......?","JPN":"これ……絵本？　とても古い本みたい……","ENG":"Hmm... Is this some kind of a story book? It looks really old...","TWN":"這是……童話書嗎？看起來很舊啊……？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"내용은 나도 몰라. 읽어 본 적이 없거든.","JPN":"内容は妾も知らない。読んだことがないからな。","ENG":"I don't know what's inside. I've never read it.","TWN":"裡面的內容我也不太清楚，我沒看過。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 왜 안 읽어 보셨는데요?","JPN":"え？　なんで読まなかったんですか？","ENG":"Huh? Why not?","TWN":"啊？為什麼沒看？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"글쎄, 너도 책을 펼쳐 보면 알게 될 걸.","JPN":"汝も本を開いてみればわかるはずだ。","ENG":"You'll find out when you open it up.","TWN":"這個嗎，妳打開看看就知道了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"책을 펼쳐요? 이렇게?","JPN":"本を開く？　こうですか？","ENG":"Open it up? Like this?","TWN":"打開？是這樣開嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗뜨뜨뜨?!","JPN":"あっつい！？","ENG":"Ow! That's hot!","TWN":"啊，燙燙燙？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"봤지?","JPN":"どうだ。","ENG":"See?","TWN":"知道了吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"뭐, 뭐예요? 갑자기 불길이 솟구쳤어요!","JPN":"な、何！？　急に炎が燃え上がった！","ENG":"W-what was that? Flames shot out of the book!","TWN":"這，這怎麼回事？突然就冒火了！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이 책의 이름은 <color=#ffd34c>솔라 코덱스</color>야.","JPN":"この本のタイトルは<color=#ffd34c>ソーラーコーデックス</color>だ。","ENG":"That book is called the <color=#ffd34c>Solar Codex</color>.","TWN":"這本書叫<color=#ffd34c>太陽法典</color>。"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"책에 깃든 존재에게 인정 받아야만 펼칠 수 있는 고대의 마도서지.","JPN":"本に宿る存在に認められると開くことのできる古代の魔導書だ。","ENG":"Only those who are deemed worthy by the being imbued inside that ancient tome can read it.","TWN":"這是只有被蘊含在書本裡的存在所認可過的人，才能打開的古代魔導書。"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"내가 아는 마녀들 중에 이 책을 펼칠 수 있었던 사람은 메이 할머니뿐이었어.","JPN":"妾が知っている魔女の中でこの本を開くことができた人は、メイ婆さんしかいなかった。","ENG":"Granny May was the only witch I knew who could open the book.","TWN":"在我認識的魔女中，能打開這本書的只有梅伊奶奶。"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"인정 받지 않은 사람들이 억지로 책을 펼치려 하면 그대로 불꽃에 삼켜지게 돼.","JPN":"認められていない人が無理に本を開こうとすると、本はそのまま炎に呑み込まれてしまうのだ。","ENG":"Anyone else would get engulfed in flames if they tried to force it open.","TWN":"如果沒有被認可的人強行打開這本書，就會被火焰吞噬。"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"네가 방금 경험한 것처럼 말이야.","JPN":"汝が今経験したようにな。","ENG":"Like what happened to you just now.","TWN":"就像剛才那樣。"},"stage":{"bg":"SS_STREGA_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그런 건 그냥 말로 해도 될 텐데......","JPN":"私が本を開く前に教えてくれればよかったのに……","ENG":"You could have told me about that...","TWN":"妳怎麼不直接告訴我啊……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"사람은 원래 말로 하면 잘 못 알아먹거든.","JPN":"人間は言葉で伝えてもよく理解できないからな。","ENG":"People never learn if you just tell them.","TWN":"人嘛，有時候光靠說是不會聽的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"위험한 마도구를 멋대로 건드려 놓고 뒷수습을 못하는 바보들이 한둘이 아니니까.","JPN":"危険な魔導書を勝手に触っておいて、後片付けできない馬鹿は大勢いるんだ。","ENG":"Too many fools have wreaked havoc after messing with dangerous magic items against all warnings.","TWN":"擅自觸碰魔導具後闖下大禍的傻瓜可不只有一兩個。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그런 녀석들은 본인이 한 번 당해봐야 말귀를 잘 듣더라고.","JPN":"そんな奴らは一度痛い目に合わないと理解できないからな。","ENG":"They only start listening to you once they've experienced the consequences themselves.","TWN":"那樣的傢伙，最好是讓他們親自體驗一番，才會乖乖聽話。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"네가 메이 할머니만큼 대단한 마녀가 될 수 있을지 어떨지는 나도 몰라.","JPN":"汝がメイ婆さんみたいな魔女になれるかどうかは、妾にもわからない。","ENG":"I have no idea if you'll become a great witch like Granny May.","TWN":"我不知道妳能不能成為像梅伊奶奶那麼了不起的魔女。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하지만 열심히 하면 뭐, 언젠가 그 책에 인정 받을 가능성도 있겠지.","JPN":"だが頑張れば、まぁ、いつかその本に認められるかもしれない。","ENG":"But if you keep working hard, maybe that book will deem you worthy one day.","TWN":"但如果努力的話，遲早有一天那本書會認可你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그러니 잘 간직하도록 해.","JPN":"だから大切に保管しておくように。","ENG":"So hang onto it.","TWN":"所以，收好這本書吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저, 점장님......!","JPN":"て、店長……！","ENG":"L-Laura!","TWN":"店、店長……！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"왜, 왜 그렇게 울먹거려? 화상이라도 입은 거야?","JPN":"な、なんで泣きそうな顔をしてるんだ？　火傷でもしたか？","ENG":"W-why are you getting all teary? Did you get burned?","TWN":"妳，妳哭什麼？是被燒傷了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"제가 정식 마녀가 될 수 있게 응원해 주는 거죠?!","JPN":"私が正式な魔女になるまで、応援してくれるんですか？","ENG":"So you want me to become a witch, right?","TWN":"妳這是在鼓勵我成為正式魔女對不對？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"고맙습니다! 반드시 할머니의 마도서에게 인정 받을 수 있는 훌륭한 마녀가 될게요!","JPN":"ありがとうございます！　お婆ちゃんの魔導書に認めてもらえるように、必ず立派な魔女になります！","ENG":"Thank you! I'll try my best to become a witch deemed worthy by grandma's tome!","TWN":"謝謝！我一定會得到這本魔導書的認可，成為優秀的魔女！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그, 그래...... 긍정적이라 좋네.","JPN":"そ、そうか……前向きでよかった。","ENG":"S-sure... I applaud the optimism.","TWN":"好，好啊……樂觀的態度很不錯。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그런데 막 끌어안지는 말아 줄래? 우리 그렇게 친한 사이도 아니잖아?","JPN":"でも、急に抱きしめるのはやめてくれないか？　そんなに仲の良い間柄でもないだろう。","ENG":"But can you not hug me like this? We're not that close.","TWN":"可是妳能不能不要抱我？我們好像沒那麼熟吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗, 네! 죄송해요! 너무 감동스러워서......!","JPN":"あっ！　ごめんなさい！　感動しすぎて……！","ENG":"Oh, sorry! I was just so moved!","TWN":"啊，好的！抱歉！我太感動了……！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국에서 알려드립니다.</color>","JPN":"<color=#ffd34c>都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is an announcement from City Management.</color>","TWN":"<color=#ffd34c>城市管理局通知。</color>"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>오늘 발생한 침식 경보는 모두 해제되었습니다.</color>","JPN":"<color=#ffd34c>本日発表した侵食警報はすべて解除されました。</color>","ENG":"<color=#ffd34c>Today's Corruption alert is now lifted.</color>","TWN":"<color=#ffd34c>今天發生的侵蝕警報已全部解除。</color>"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시 경비를 담당한 태스크포스가 안전을 확인하였으니, 시민 여러분은 안심하시고 할로윈 축제를 즐겨 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>都市警備担当のタスクフォースが安全を確認いたしましたので、\\n市民の皆さんは安心してハロウィンをお楽しみください。</color>","ENG":"<color=#ffd34c>The TASKFORCEs in charge of city security have verified that it is now safe for you to enjoy the Halloween festival.</color>","TWN":"<color=#ffd34c>負責城市警備的特遣勢力已確認安全，各位市民可安心享受萬聖節慶典。</color>"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"들었지?","JPN":"聞いたな？","ENG":"Hear that?","TWN":"聽到了吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그동안 옷 만들고 침식체 쫓느라 수고 많았어.","JPN":"今まで衣装製作や侵食体の退治などご苦労だった。","ENG":"I know you've been working hard trying to make clothes and fend off the C.O.s.","TWN":"一下要做衣服，一下又要趕走侵蝕體，真是辛苦妳了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"오늘은 이제 카페도 휴업이야. 남은 시간은 축제에서 즐겁게 보내.","JPN":"今日はカフェもお休みだ。あとは祭りを楽しんでくれ。","ENG":"The cafe is closed for today. Enjoy the rest of the day at the festival.","TWN":"今天咖啡店休一天，妳去享受慶典吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네! 그럼 이따가 할로윈 코스튬 경연장에서 봐요!","JPN":"はい！　ハロウィンコスチュームコンテストで会いましょう！","ENG":"Thanks! I'll see you at the costume contest then!","TWN":"嗯！等會兒在萬聖節扮裝大會賽場見！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"솔라 코덱스를 넘겨 주다니, 너무 이른 거 아냐?","JPN":"ソーラーコーデックスを渡すなんて早すぎるんじゃない？","ENG":"You sure it's not too early to hand her the Solar Codex?","TWN":"把太陽法典給她，是不是太早了？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그 마도서는 발푸르기스 성을 둘러싼 결계의 핵심이잖아.","JPN":"あの魔導書はヴァルプルギス城を取り囲む結界の要でしょう？","ENG":"That tome is the key to the barrier around Walpurgis Castle.","TWN":"魔導書是設置在魔女之夜城結界的核心。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"메이 할머니가 돌아가셨으니 어차피 이제는 애물단지에 불과해.","JPN":"メイ婆さんが亡くなった以上、今は厄介物に過ぎない。","ENG":"It's of little use to us now that Granny May's gone.","TWN":"梅伊奶奶去世了，我們留著那本書也沒什麼用。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"사용자를 불태워 버리는 마도서를 대체 어디 써먹겠어?","JPN":"使い手を燃やしてしまう魔導書なんか使い道がないだろう。","ENG":"What else can we do with a book that turns you into barbecue?","TWN":"胡亂燒人的魔導書留著也無用啊？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그건 그렇지만...... 아무것도 모르는 애한테 큰 짐을 덥석 떠넘긴 느낌이야.","JPN":"それはそうだけど……何も知らないあの子に\\n突然大きな負担をかけたような気がするわ。","ENG":"Still... I feel like we've placed such a heavy burden on the kid. And she doesn't know anything yet.","TWN":"話雖如此……但總感覺我們把包袱丟給了什麼都不懂的小孩子。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여태까지 우리가 해 본 시도들은 모두 실패했잖아.","JPN":"今まで妾たちがやってきたことは全部失敗しただろう。","ENG":"All our attempts have failed so far.","TWN":"至今為止，我們所有的嘗試都失敗了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이제는 저 애가 마도서를 사용할 수 있길 바라는 수밖에 없어.","JPN":"もうあの子が魔導書を使えるようになることを願うしかない。","ENG":"Our only hope is for her to figure out how to read that tome.","TWN":"現在就只能把希望寄託在那個孩子身上了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그동안 봉인 수복은 어떻게든 다른 마도구로 때워야지, 뭐.","JPN":"それまで封印の修復は他の魔導書でなんとかするしかないがな。","ENG":"In the meantime, we'll have to resort to other means to patch up the barrier.","TWN":"在那之前，就儘量用其他魔導具修復結界吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"저 아이가 해낼 수 있을까?","JPN":"あの子にできるのかしら？","ENG":"Do you think she can pull it off?","TWN":"她能做到嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......메이 할머니의 손녀잖아.","JPN":"……メイ婆さんの孫だからな。","ENG":"She's Granny May's granddaughter.","TWN":"……她可是梅伊奶奶的孫女啊。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"해낼 거야.","JPN":"やれると思う。","ENG":"I'm sure she will.","TWN":"一定可以的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};